ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?municipality ?foreign_born_population WHERE {
  ?population a :Population .
  ?population p:Municipality ?municipality .
  ?population p:Foreign_born_Population ?foreign_born_population .
  ?population p:Total_Population ?total_population_f .
  FILTER(?total_population_f > 60000)
} }
  full: { SELECT ?municipality ?foreign_born_population ?naturalized_citizens WHERE {
  ?population a :Population .
  ?population p:Municipality ?municipality .
  ?population p:Foreign_born_Population ?foreign_born_population .
  ?population p:Naturalized_Citizens ?naturalized_citizens .
  ?population p:Total_Population ?total_population_f .
  FILTER(?total_population_f > 60000)
} }
  component_2: { SELECT ?municipality ?naturalized_citizens WHERE {
  ?population a :Population .
  ?population p:Municipality ?municipality .
  ?population p:Naturalized_Citizens ?naturalized_citizens .
  ?population p:Total_Population ?total_population_f .
  FILTER(?total_population_f > 60000)
} }
}

PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?naturalized_citizens ?municipality WHERE {
  ?population a :Population .
  ?population p:Naturalized_Citizens ?naturalized_citizens .
  ?population p:Municipality ?municipality .
} }
  component_2: { SELECT ?foreign_born_population ?municipality WHERE {
  ?population a :Population .
  ?population p:Foreign_born_Population ?foreign_born_population .
  ?population p:Municipality ?municipality .
} }
  full: { SELECT ?foreign_born_population ?naturalized_citizens ?municipality WHERE {
  ?population a :Population .
  ?population p:Foreign_born_Population ?foreign_born_population .
  ?population p:Naturalized_Citizens ?naturalized_citizens .
  ?population p:Municipality ?municipality .
} }
}
